t.script:
(function () {
    "use strict";
    if (window.location.pathname.indexOf('/petunjuk-arah') === -1) return;

    // ---- v3.10.27: inject page-specific CSS ----
    // (Popup color override + CTA button CSS are injected
    // globally by footer_map_maplibre.xml. Here we only
    // add page-specific styles for the directions UI.)
    (function injectDirectionsCSS() {
        if (document.getElementById('wl-directions-css')) return;
        var style = document.createElement('st' + 'yle');
        style.id = 'wl-directions-css';
        style.textContent =
            // User position marker (pulsing blue dot)
            '.wl-user-marker {' +
                'width: 24px; height: 24px; position: relative;' +
            '}' +
            '.wl-user-marker__dot {' +
                'position: absolute; top: 0; left: 0;' +
                'width: 24px; height: 24px;' +
                'background: #1976d2;' +
                'border: 3px solid #fff;' +
                'border-radius: 50%;' +
                'box-shadow: 0 0 6px rgba(0,0,0,0.4);' +
                'z-index: 2;' +
            '}' +
            '.wl-user-marker__pulse {' +
                'position: absolute; top: 0; left: 0;' +
                'width: 24px; height: 24px;' +
                'background: #1976d2;' +
                'border-radius: 50%;' +
                'opacity: 0.5;' +
                'animation: wl-user-pulse 1.8s ease-out infinite;' +
                'z-index: 1;' +
            '}' +
            '@keyframes wl-user-pulse {' +
                '0% { transform: scale(1); opacity: 0.5; }' +
                '70% { transform: scale(2.6); opacity: 0; }' +
                '100% { transform: scale(2.6); opacity: 0; }' +
            '}' +
            // Big direction arrow animation (bouncing toward destination)
            '.wl-direction-arrow-bounce {' +
                'animation: wl-arrow-bounce 1.2s ease-in-out infinite;' +
            '}' +
            '@keyframes wl-arrow-bounce {' +
                '0%, 100% { transform: translateY(0) rotate(var(--wl-arrow-rot, 0deg)); }' +
                '50% { transform: translateY(-12px) rotate(var(--wl-arrow-rot, 0deg)); }' +
            '}';
        document.head.appendChild(style);
        console.log('WL: directions page CSS injected');
    })();

    // Warung Lakku cabang location (same as footer + modal)
    var WL_DEST = { lat: -8.188092, lng: 112.356862 };

    var BEARING_LABELS = [
        'Utara', 'Timur Laut', 'Timur', 'Tenggara',
        'Selatan', 'Barat Daya', 'Barat', 'Barat Laut'
    ];
    function bearingLabel(deg) {
        deg = ((deg % 360) + 360) % 360;
        return BEARING_LABELS[Math.round(deg / 45) % 8];
    }
    function haversine(lat1, lng1, lat2, lng2) {
        var R = 6371000;
        var toRad = Math.PI / 180;
        var dLat = (lat2 - lat1) * toRad;
        var dLng = (lng2 - lng1) * toRad;
        var a = Math.sin(dLat/2) * Math.sin(dLat/2) +
                Math.cos(lat1 * toRad) * Math.cos(lat2 * toRad) *
                Math.sin(dLng/2) * Math.sin(dLng/2);
        return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    }
    function bearing(lat1, lng1, lat2, lng2) {
        var toRad = Math.PI / 180, toDeg = 180 / Math.PI;
        var phi1 = lat1 * toRad, phi2 = lat2 * toRad;
        var dLambda = (lng2 - lng1) * toRad;
        var y = Math.sin(dLambda) * Math.cos(phi2);
        var x = Math.cos(phi1) * Math.sin(phi2) -
                Math.sin(phi1) * Math.cos(phi2) * Math.cos(dLambda);
        return (Math.atan2(y, x) * toDeg + 360) % 360;
    }
    function formatDistance(m) {
        if (m < 1000) return Math.round(m) + ' m';
        return (m / 1000).toFixed(2) + ' km';
    }
    function formatEta(m) {
        var seconds = m / 1.389;  // 5 km/h walking speed
        if (seconds < 60) return '< 1 mnt';
        var mins = Math.floor(seconds / 60);
        if (mins < 60) return mins + ' mnt';
        var hrs = Math.floor(mins / 60);
        return hrs + 'j ' + (mins % 60) + 'm';
    }

    var map = null, userMarker = null, destMarker = null;
    var lineLayer = 'wl-directions-line';
    var lineSource = 'wl-directions-line';

    function loadMapLibre(cb) {
        if (window.maplibregl) { cb(); return; }
        if (window._wlMapLibreLoading) {
            window._wlMapLibreCallbacks = window._wlMapLibreCallbacks || [];
            window._wlMapLibreCallbacks.push(cb); return;
        }
        window._wlMapLibreLoading = true;
        window._wlMapLibreCallbacks = [cb];
        var link = document.createElement('link');
        link.rel = 'stylesheet';
        link.href = 'https://unpkg.com/maplibre-gl@4.7.1/dist/maplibre-gl.css';
        document.head.appendChild(link);
        var s = document.createElement('script');
        s.src = 'https://unpkg.com/maplibre-gl@4.7.1/dist/maplibre-gl.js';
        s.async = true;
        s.onload = function () {
            var cbs = window._wlMapLibreCallbacks;
            window._wlMapLibreCallbacks = [];
            for (var i = 0; i < cbs.length; i++) {
                try { cbs[i](); } catch (e) { console.warn(e); }
            }
        };
        document.head.appendChild(s);
    }

    function applyCustomMapStyle(m) {
        if (!m || !m.getStyle) return;
        var layers = m.getStyle().layers || [];
        for (var i = 0; i < layers.length; i++) {
            var layer = layers[i];
            var sl = layer['source-layer'] || '';
            var lid = layer.id || '';
            if (layer.type === 'line' && sl === 'transportation') {
                var color = '#7a0c14';
                if (lid.indexOf('casing') !== -1) color = '#5a080e';
                else if (lid.indexOf('minor') !== -1 ||
                         lid.indexOf('path') !== -1 ||
                         lid.indexOf('pier') !== -1) color = '#a02030';
                try { m.setPaintProperty(lid, 'line-color', color); } catch (e) {}
            }
            if ((layer.type === 'fill' && sl === 'water') ||
                (layer.type === 'line' && sl === 'waterway')) {
                try {
                    if (layer.type === 'fill') m.setPaintProperty(lid, 'fill-color', '#cfe4f5');
                    else m.setPaintProperty(lid, 'line-color', '#a8d0ed');
                } catch (e) {}
            }
            if (layer.type === 'fill' && sl === 'building') {
                try {
                    m.setPaintProperty(lid, 'fill-color', '#fff7e0');
                    m.setPaintProperty(lid, 'fill-opacity', 0.9);
                } catch (e) {}
            }
            if (layer.type === 'fill' && sl === 'landuse') {
                try { m.setPaintProperty(lid, 'fill-color', '#e8f5e8'); } catch (e) {}
            }
        }
    }

    function makeUserMarker() {
        var el = document.createElement('div');
        el.className = 'wl-user-marker';
        el.innerHTML =
            '<div class="wl-user-marker__pulse"></div>' +
            '<div class="wl-user-marker__dot"></div>';
        return el;
    }
    function makeDestMarker() {
        var el = document.createElement('div');
        el.className = 'wl-cabang-marker';
        el.innerHTML =
            '<div class="wl-cabang-marker__pin">' +
                '<i class="fa fa-shopping-bag"></i>' +
            '</div>' +
            '<div class="wl-cabang-marker__label">' +
                '<strong>WARUNG LAKKU</strong>' +
                '<span>Cabang Binangun</span>' +
            '</div>';
        return el;
    }

    function updateLine(userLat, userLng) {
        if (!map) return;
        var data = {
            type: 'Feature',
            geometry: {
                type: 'LineString',
                coordinates: [
                    [userLng, userLat],
                    [WL_DEST.lng, WL_DEST.lat]
                ]
            }
        };
        if (map.getSource(lineSource)) {
            map.getSource(lineSource).setData(data);
        } else {
            map.addSource(lineSource, { type: 'geojson', data: data });
            map.addLayer({
                id: lineLayer,
                type: 'line',
                source: lineSource,
                paint: {
                    'line-color': '#7a0c14',
                    'line-width': 3,
                    'line-dasharray': [2, 2],
                    'line-opacity': 0.8
                }
            });
        }
    }

    function updateInfo(userLat, userLng, accuracy) {
        var dist = haversine(userLat, userLng, WL_DEST.lat, WL_DEST.lng);
        var bear = bearing(userLat, userLng, WL_DEST.lat, WL_DEST.lng);

        var distEl = document.getElementById('wl-directions-distance');
        var bearEl = document.getElementById('wl-directions-bearing');
        var etaEl  = document.getElementById('wl-directions-eta');
        var accEl  = document.getElementById('wl-directions-accuracy');
        if (distEl) distEl.textContent = formatDistance(dist);
        if (bearEl) bearEl.textContent = bearingLabel(bear) + ' (' + Math.round(bear) + '\u00B0)';
        if (etaEl)  etaEl.textContent = formatEta(dist);
        if (accEl)  accEl.textContent = '\u00B1' + Math.round(accuracy) + ' m';

        // Update big arrow rotation.
        // Arrow-up icon at rotate(0deg) points to top of screen = NORTH.
        // Bearing 90 = EAST = arrow should point right = rotate(90deg) clockwise.
        // So rotate by the bearing angle directly.
        var bigArrow = document.getElementById('wl-directions-arrow-big');
        if (bigArrow) {
            bigArrow.style.setProperty('--wl-arrow-rot', bear + 'deg');
            bigArrow.style.transform = 'rotate(' + bear + 'deg)';
            bigArrow.classList.add('wl-direction-arrow-bounce');
        }
        var hint = document.getElementById('wl-directions-hint');
        if (hint) {
            if (dist < 50) {
                hint.innerHTML = '<i class="fa fa-check-circle me-1" style="color:#25d366"></i> Anda sudah dekat Warung Lakku!';
            } else {
                hint.innerHTML = 'Ikuti arah panah menuju Warung Lakku (<strong>' + formatDistance(dist) + '</strong> lagi).';
            }
        }
    }

    function onPosition(pos) {
        var lat = pos.coords.latitude;
        var lng = pos.coords.longitude;
        var acc = pos.coords.accuracy || 0;

        var info = document.getElementById('wl-directions-info');
        if (info) info.style.display = 'block';
        var banner = document.getElementById('wl-directions-arrow-banner');
        if (banner) banner.style.display = 'block';

        var status = document.getElementById('wl-directions-status');
        if (status) {
            status.innerHTML = '<i class="fa fa-check-circle me-2" style="color:#25d366"></i>Lokasi aktif \u00B7 presisi \u00B1' + Math.round(acc) + ' m';
            status.style.background = 'rgba(40, 167, 69, 0.25)';
            status.style.borderColor = '#28a745';
        }

        if (!map) return;

        if (!userMarker) {
            userMarker = new maplibregl.Marker({
                element: makeUserMarker(),
                rotationAlignment: 'viewport',
                pitchAlignment: 'viewport'
            })
                .setLngLat([lng, lat])
                .addTo(map);
            var bounds = new maplibregl.LngLatBounds();
            bounds.extend([lng, lat]);
            bounds.extend([WL_DEST.lng, WL_DEST.lat]);
            map.fitBounds(bounds, {
                padding: { top: 60, bottom: 60, left: 60, right: 60 },
                duration: 1500
            });
        } else {
            userMarker.setLngLat([lng, lat]);
        }

        updateLine(lat, lng);
        updateInfo(lat, lng, acc);
    }

    function onPositionError(err) {
        console.warn('WL: geolocation error:', err);
        var status = document.getElementById('wl-directions-status');
        if (status) {
            status.innerHTML = '<i class="fa fa-exclamation-triangle me-2" style="color:#ffc107"></i>Lokasi tidak tersedia';
            status.style.background = 'rgba(255, 193, 7, 0.25)';
            status.style.borderColor = '#ffc107';
        }
        var errorBox = document.getElementById('wl-directions-error');
        var errorMsg = document.getElementById('wl-directions-error-msg');
        var mapWrap = document.getElementById('wl_directions_map');
        var banner = document.getElementById('wl-directions-arrow-banner');
        var info = document.getElementById('wl-directions-info');
        if (errorBox) errorBox.style.display = 'block';
        if (mapWrap) mapWrap.style.display = 'none';
        if (banner) banner.style.display = 'none';
        if (info) info.style.display = 'none';
        if (errorMsg) {
            var msg = 'Tidak dapat mengakses lokasi Anda. ';
            if (err && err.code === 1) msg += 'Izin lokasi ditolak. Silakan aktifkan izin di pengaturan browser, lalu muat ulang.';
            else if (err && err.code === 2) msg += 'Posisi tidak tersedia (GPS mungkin sedang dimatikan atau lemah).';
            else if (err && err.code === 3) msg += 'Waktu permintaan lokasi habis. Coba lagi di area terbuka.';
            else msg += 'Pastikan GPS aktif dan browser diizinkan mengakses lokasi.';
            errorMsg.textContent = msg;
        }
    }

    function initMap() {
        var container = document.getElementById('wl_directions_map');
        if (!container) return;
        container.innerHTML = '';

        loadMapLibre(function () {
            if (!window.maplibregl) {
                console.warn('WL: maplibregl failed to load');
                return;
            }
            map = new maplibregl.Map({
                container: container,
                style: 'https://tiles.openfreemap.org/styles/liberty',
                center: [WL_DEST.lng, WL_DEST.lat],
                zoom: 13,
                bearing: 0, pitch: 0, maxPitch: 0,
                attributionControl: true,
                dragRotate: false, touchPitch: false,
                pitchWithRotate: false, touchZoomRotate: true,
                scrollZoom: true
            });
            try { map.touchZoomRotate.disableRotation(); } catch (e) {}
            try { map.keyboard.disableRotation(); } catch (e) {}
            map.on('rotate', function () {
                if (map.getBearing() !== 0) map.setBearing(0);
            });
            map.on('pitch', function () {
                if (map.getPitch() !== 0) map.setPitch(0);
            });
            map.on('styledata', function () { applyCustomMapStyle(map); });

            map.on('load', function () {
                applyCustomMapStyle(map);

                destMarker = new maplibregl.Marker({
                    element: makeDestMarker(),
                    anchor: 'bottom',
                    rotationAlignment: 'viewport',
                    pitchAlignment: 'viewport'
                })
                    .setLngLat([WL_DEST.lng, WL_DEST.lat])
                    .setPopup(new maplibregl.Popup({ offset: 30 }).setHTML(
                        '<div style="min-width: 200px; font-family: Poppins, sans-serif; padding: 4px; color: #333;">' +
                            '<strong style="color: #7a0c14; font-size: 14px; display: block; margin-bottom: 2px;">' +
                                '<i class="fa fa-shopping-bag" style="color: #f5c400;"></i> WARUNG LAKKU</strong>' +
                            '<span style="color: #666; font-size: 11px;">Cabang Binangun</span>' +
                            '<hr style="margin: 6px 0; border: 0; border-top: 1px solid #eee;"/>' +
                            '<div style="font-size: 12px; color: #333;">' +
                                '<i class="fa fa-map-marker" style="color: #7a0c14; width: 14px;"></i> Dusun Ngrekesan, Desa Ngadri, Kec. Binangun, Kab. Blitar</div>' +
                        '</div>'
                    ))
                    .addTo(map);

                map.addControl(new maplibregl.NavigationControl({
                    visualizePitch: false, showCompass: false, showZoom: true
                }), 'top-right');

                if (!('geolocation' in navigator)) {
                    onPositionError({ code: 0, message: 'Geolocation not supported' });
                    return;
                }
                navigator.geolocation.watchPosition(
                    onPosition,
                    onPositionError,
                    { enableHighAccuracy: true, maximumAge: 3000, timeout: 15000 }
                );

                console.log('WL: directions map ready');
            });
        });
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initMap);
    } else {
        initMap();
    }
})();
